# Ethics submission risk scorer

from dataclasses import dataclass
from typing import Literal

HarmLevel = Literal["none","low","medium","high","critical"]

HARM_WEIGHTS = {"none":0,"low":1,"medium":2,"high":3,"critical":4}
PROB_WEIGHTS = {"negligible":0.1,"unlikely":0.3,"possible":0.5,"likely":0.7,"near_certain":0.9}

@dataclass
class HarmDimension:
    name: str
    probability: str    # negligible | unlikely | possible | likely | near_certain
    magnitude: HarmLevel
    mitigation_in_place: bool
    mitigation_effectiveness: float  # 0-1; reduction in residual risk

    def raw_risk_score(self) -> float:
        return PROB_WEIGHTS[self.probability] * HARM_WEIGHTS[self.magnitude]

    def residual_risk_score(self) -> float:
        reduction = self.mitigation_effectiveness if self.mitigation_in_place else 0.0
        return round(self.raw_risk_score() * (1 - reduction), 2)

@dataclass
class EthicsRiskAssessment:
    submission_id: str
    harm_dimensions: list[HarmDimension]

    def total_residual_risk(self) -> float:
        return round(sum(d.residual_risk_score() for d in self.harm_dimensions), 2)

    def highest_risk_dimension(self) -> HarmDimension:
        return max(self.harm_dimensions, key=lambda d: d.residual_risk_score())

    def review_recommendation(self) -> str:
        score = self.total_residual_risk()
        if score <= 1.0:
            return "approve"
        elif score <= 3.0:
            return "approve_with_conditions"
        elif score <= 5.0:
            return "refer_for_technical_review"
        else:
            return "reject"

# Agentic system autonomy scope assessment

from dataclasses import dataclass
from typing import Literal

@dataclass
class AgentActionScope:
    action_category: str   # e.g. "send_email","place_order","delete_record"
    max_value_gbp: float   # financial value ceiling; 0 if non-financial
    requires_human_approval: bool
    reversible: bool
    external_facing: bool  # does it affect parties outside the org?
    data_sensitivity: Literal["none","internal","confidential","restricted"]

    def autonomy_risk_level(self) -> str:
        if self.requires_human_approval:
            return "low"
        if not self.reversible and self.external_facing:
            return "critical"
        if self.max_value_gbp > 10_000:
            return "high"
        if self.data_sensitivity in ("confidential","restricted"):
            return "high"
        if not self.reversible:
            return "medium"
        return "low"

def agent_autonomy_report(actions: list[AgentActionScope]) -> dict:
    levels = [a.autonomy_risk_level() for a in actions]
    return {
        "total_action_types": len(actions),
        "high_or_critical": sum(1 for l in levels if l in ("high","critical")),
        "irreversible_external": sum(1 for a in actions if not a.reversible and a.external_facing),
        "max_autonomous_value_gbp": max((a.max_value_gbp for a in actions if not a.requires_human_approval), default=0),
        "overall_risk": "critical" if "critical" in levels else "high" if "high" in levels else "medium" if "medium" in levels else "low",
    }
